  ('heelevel3-d0d1b9a2-moex-00461', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-f6c431ec', 'sub-heelevel3-d0d1b9a2-04', NULL, 'single_choice', '政府打算開放某產業的特許執照，該產業的經濟租為600億元，根據杜洛克（G.Tullock）的競租 理論，當競租者人數趨近於無窮大時，社會的總競租支出將趨近於多少？', '["150億元", "300億元", "600億元", "1200億元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": "b3991257716c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
